import { AnchorHTMLAttributes, MouseEvent, PropsWithChildren, useCallback } from 'react';
import { SummaryArticle, useSelector } from '@topwrite/common';
import { history } from '@/lib/history';
import { parsePath, PartialPath } from 'history';
import useArticle from '@/lib/use-article';

interface LinkProps {
    to: string | SummaryArticle
}

export default function Link({
    children,
    to,
    className,
    ...props
}: PropsWithChildren<LinkProps & Omit<AnchorHTMLAttributes<HTMLAnchorElement>, 'href'>>) {

    const file = useSelector('file');
    const article = useArticle();

    if (to instanceof SummaryArticle) {
        to = to.getPath();
    }

    let href;
    if (to) {
        href = file.relative(to);
    }

    const clickHandler = useCallback((e: MouseEvent<HTMLAnchorElement>) => {
        e.preventDefault();
        if (!article || article.getPath() !== to) {
            const location: PartialPath = {
                pathname: '',
                search: '',
                hash: '',
                ...parsePath(e.currentTarget.href)
            };
            history.push(location);
        }
    }, [article, to]);

    return <a {...props} onClick={clickHandler} className={className} href={href}>{children}</a>;
}
