import { Markdown as CommonMarkdown } from '@topwrite/common';
import { useEffect } from 'react';
import { history } from '@/lib/history';

type MarkdownProps = Parameters<typeof CommonMarkdown>[0]

export default function Markdown({ children, ...props }: MarkdownProps) {

    useEffect(() => {
        const hash = history.location.hash;
        if (hash) {
            const anchor = document.getElementById(decodeURIComponent(hash).substr(1));
            if (anchor) {
                window.scrollTo(0, anchor.offsetTop);
            }
        }
    }, []);

    return <CommonMarkdown {...props}>
        {children}
    </CommonMarkdown>;
}
